// Sigma 3.9 - KeepSprint.java (cancel STOP_SPRINTING)
// Reproduced from actual 1.8.9 client source
@EventTarget
public void onPacket(EventPacket ep) {
  if (ep.isIncoming() && ep.getPacket() instanceof C0BPacketEntityAction) {
    C0BPacketEntityAction packet =
      (C0BPacketEntityAction) ep.getPacket();
    if (packet.getAction() ==
      C0BPacketEntityAction.Action.STOP_SPRINTING) {
      // Keep player sprinting regardless of server
      ep.setCancelled(true);
    }
  }
}

